const relayPort = stack.getPort();
const relayBaseUrl = `http://127.0.0.1:${relayPort}`;

// Snapshot existing sessions so we can clean up only those created during tests.
// The initial session (created by createRelayStack) is NOT pre-existing — it
// should be deleted on teardown along with any sessions created via the UI.
const initialSessionId = stack.sessionMgr.getActiveSessionId();
const sessionsAtStartup = await stack.client.listSessions();
const preExistingIds = new Set(sessionsAtStartup.map((s) => s.id));
// The initial session was just created — remove it from the pre-existing set
// so it gets cleaned up too.
if (initialSessionId) preExistingIds.delete(initialSessionId);

// Switch to free-tier model for cost-free E2E testing
await switchToFreeModel(relayPort);

return {
	stack,
	opencodeUrl,
	relayPort,
	relayBaseUrl,
	model: E2E_MODEL,
	provider: E2E_PROVIDER,
	async stop(): Promise<void> {
		// Delete sessions created during this test run (initial + UI-created).
		// Pre-existing sessions are left untouched.
		try {
			const allSessions = await stack.client.listSessions();
			for (const s of allSessions) {
				if (!preExistingIds.has(s.id)) {
					await stack.client.deleteSession(s.id);
				}
			}
		} catch {
			// Best-effort cleanup — don't fail teardown
		}
		await stack.stop();
	},
};

